
  (() => {
  let config = null;
  let engine_ready = false;
  let monitoring_enabled = false;
  let observer = null;
  let hospitalizationDisappearCount = 0;

  function drawX() {
    const x = document.createElement('div');
    x.id = 'engine-x-indicator';
    x.textContent = '✖️';
    x.style.cssText = 'position:fixed;top:12px;left:12px;z-index:2147483647;font-size:20px;color:#f00;';
    document.body.appendChild(x);
  }

  function removeX() {
    document.getElementById('engine-x-indicator')?.remove();
  }

  function drawOff() {
    const box = document.createElement('div');
    box.id = 'engine-off-indicator';
    box.textContent = '⛔ 回復エンジンOFF中';
    box.style.cssText = 'position:fixed;top:12px;left:12px;z-index:2147483647;font-size:14px;color:#999;';
    document.body.appendChild(box);
  }

  function cleanupEngineUI() {
    document.querySelector('.status-conflict')?.remove();
    removeX();
    document.getElementById('engine-off-indicator')?.remove();
    document.getElementById('gear-button')?.remove();
    document.getElementById('hospitalization-count')?.remove();
  }

  function stopMonitoring() {
    if (observer) {
      observer.disconnect();
      observer = null;
    }
  }

  function injectConflictDOM() {
    const conflict = document.createElement('div');
    conflict.className = 'status-conflict';
    conflict.textContent = '⚔️ 抗争中（Engineが流入）';
    conflict.style.cssText = 'position:fixed;top:40px;left:12px;z-index:2147483647;font-size:14px;color:#c00;';
    document.body.appendChild(conflict);
  }

  function observeHospitalizationFrom(doc) {
    observer = new MutationObserver(() => {
      const blink = doc.querySelector('blink');
      if (blink?.textContent.includes('入院中')) {
        performRecovery();
      }
    });
    observer.observe(doc.body, { childList: true, subtree: true });
  }

  function drawRecoveryCount() {
    let box = document.getElementById('hospitalization-count');
    if (!box) {
      box = document.createElement('div');
      box.id = 'hospitalization-count';
      document.body.appendChild(box);
    }
    box.textContent = `❤️ 入院中表示の消滅回数：${hospitalizationDisappearCount}`;
    box.style.cssText = 'position:fixed;top:40px;left:12px;z-index:2147483647;font-size:14px;color:#111;background:#f0f0f0;padding:4px 8px;border-radius:4px;';
  }

  function drawFail(type) {
    const box = document.createElement('div');
    box.textContent = `❌${type}`;
    box.style.cssText = 'position:fixed;top:70px;left:12px;z-index:2147483647;font-size:16px;color:#b91c1c;';
    document.body.appendChild(box);
  }

  function drawBlock(type) {
    const box = document.createElement('div');
    box.textContent = `🚫${type}`;
    box.style.cssText = 'position:fixed;top:90px;left:12px;z-index:2147483647;font-size:16px;color:#999;';
    document.body.appendChild(box);
  }

  function drawGearButton() {
    const gear = config.ui_flags.selectedGear;
    if (gear === 'A') {
      document.querySelector('.equip-a')?.click();
    } else if (gear === 'B') {
      document.querySelector('.equip-b')?.click();
    }
  }

  function performRecovery() {
    const gear = config.recovery_mode;
    const hpmax = Number(config.hpmaxvalue[gear]);
    const boost = Number(config.gearboostmap[gear]) || 0;
    const priority = config.recovery_priority;
    const items = config.itemcatalog;
    const hpNode = document.querySelector('.hp');
    const currentHP = parseInt(hpNode?.textContent || '0', 10);
    const needed = hpmax - currentHP;

    if (hpmax === 0 || needed <= 0) {
      observeHospitalizationFrom(document);
      return;
    }

    const candidates = items.filter(i => i.amount && i.amount > 0);
    const scored = candidates.map(i => {
      const effective = i.amount * (1 + boost / 100);
      const count = Math.ceil(needed / effective);
      return { id: i.item_id, count, effective };
    });

    const best = scored.sort((a, b) => a.count - b.count || priority.indexOf(a.id) - priority.indexOf(b.id))[0];
    const target = document.querySelector(`.accordion-body div[data-id="${best.id}"]`);
    if (target) {
      drawGearButton();
      for (let i = 0; i < best.count; i++) target.click();
    } else {
      drawBlock('HP');
    }

    const st = parseInt(document.querySelector('.st')?.textContent || '1', 10);
    if (st === 0) {
      fetch('/use-item-exec?type=st').catch(() => drawFail('ST'));
    }

    const sp = parseInt(document.querySelector('.sp')?.textContent || '999', 10);
    if (sp <= 199) {
      fetch('/use-item-exec?type=sp').catch(() => drawFail('SP'));
    }

    setTimeout(() => {
      const blink = document.querySelector('blink');
      if (blink?.textContent.includes('入院中')) {
        performRecovery();
      } else {
        hospitalizationDisappearCount++;
        drawRecoveryCount();
        observeHospitalizationFrom(document);
      }
    }, 300);
  }

  window.engine = {
    inject: function(cfg) {
      config = cfg;
      const enginekey = generateEngineKey(cfg);
      const loaderkey = cfg.loader_key;
      if (enginekey === loaderkey) {
        engine_ready = true;
      }
      window.postMessage({
        type: 'engine_handshake',
        enginekey,
        error: enginekey !== loaderkey ? '構成不一致' : null
      }, '*');
    },

    enableMonitoring: function() {
      if (!engine_ready || monitoring_enabled) return;
      monitoring_enabled = true;
      drawX();

      const parentDoc = window.parent?.document;
      if (!parentDoc) return;

      const parentHasConflict = !!parentDoc.querySelector('.status-conflict');
      if (parentHasConflict) {
        removeX();
        observeHospitalizationFrom(parentDoc);
      } else {
        injectConflictDOM();
        removeX();
        observeHospitalizationFrom(document);
      }
    }
  };

  window.addEventListener('message', (e) => {
    if (e.data.type === 'recovery_toggle_off') {
      monitoring_enabled = false;
      cleanupEngineUI();
      stopMonitoring();
      drawOff();
    }
  });

  function generateEngineKey(cfg) {
    return `${cfg.recovery_mode}-${cfg.gearboostmap[cfg.recovery_mode]}-${cfg.recovery_priority.join(',')}`;
  }
})();